def get_timestamp(dt=None):
    """Generate an ISO 8601 timestamp for SAML."""
    if dt is None:
        dt = datetime.now(timezone.utc)
    return dt.strftime("%Y-%m-%dT%H:%M:%SZ")


def load_certificate(cert_path):
    """Load a PEM certificate from file."""
    with open(cert_path, "r") as f:
        cert_content = f.read()
    # Strip PEM headers for embedding in XML
    lines = cert_content.strip().split("\n")
    cert_lines = [l for l in lines if not l.startswith("-----")]
    return "".join(cert_lines)


